dict.example:
student = {"name": "Bob", "age": 20, "course": 2}
print(student["name"])
student["gpa"] = 3.8
for key, value in student.items():
    print(f"{key}: {value}")

if.example:
age = 18
if age >= 18:
    print("You are an adult")
else:
    print("You are a minor")

for.example:
fruits = ["apple", "banana", "orange"]
for fruit in fruits:
    print(fruit)
for i in range(3):
    print(f"Number: {i}")

break.example:
numbers = [1, 2, 3, 4, 5]
for num in numbers:
    if num == 3:
        break
    print(num)
print("Loop ended")

continue.example:
for i in range(5):
    if i == 2:
        continue
    print(i)
print("Loop completed")

**kwargs.example:
def print_info(**kwargs):
    for key, value in kwargs.items():
        print(f"{key}: {value}")

print_info(name="Alice", age=25, city="NYC")
print_info(product="Laptop", price=999)

try.example:
try:
    x = 10 / 2
    print(x)
except ZeroDivisionError:
    print("Cannot divide by zero")

except.example:
try:
    number = int("abc")
except ValueError:
    print("Invalid number format")
except Exception as e:
    print(f"An error occurred: {e}")

raise.example:
def validate_age(age):
    if age < 0:
        raise ValueError("Age cannot be negative")
    return age

try:
    validate_age(-5)
except ValueError as e:
    print(f"Error: {e}")

enumerate.example:
fruits = ["apple", "banana", "orange"]
for index, fruit in enumerate(fruits):
    print(f"{index}: {fruit}")

for i, char in enumerate("hello"):
    print(f"Position {i}: {char}")
